module.render:
const parse = (s) => String(s || '').trim().split('\n').map((l) => l.trim()).filter(Boolean)
  .map((l) => l.split(/[\s,]+/).map(parseFloat).filter(Number.isFinite)).filter((r) => r.length);
const secs = sections.map((s) => (s || '').trim()).filter(Boolean);
if (secs.length < 2) return `<div>(matmul: two sections — matrix A, then matrix B)</div>`;
const A = parse(secs[0]), B = parse(secs[1]);
if (!A.length || !B.length) return `<div>(matmul: rows of numbers in each section)</div>`;
if (A[0].length !== B.length) return `<div>(matmul: A is ${A.length}×${A[0].length} but B has ${B.length} rows — inner dimensions must match)</div>`;
const C = A.map((row) => B[0].map((_, j) => row.reduce((acc, v, k) => acc + v * B[k][j], 0)));
const hr = parseInt(args.row, 10) || 0, hc = parseInt(args.col, 10) || 0;
const color = args.color || 'var(--accent-color)';
const dp = parseInt(args.decimals, 10);
const decimals = Number.isFinite(dp) ? Math.max(0, Math.min(10, dp)) : 4;
const fmt = (v) => String(+v.toFixed(decimals));
const opSym = args.op ? String(args.op) : '×';
const sc = parseFloat(args.scale);
const scaleStyle = (Number.isFinite(sc) && sc !== 1) ? ` font-size:${sc}em;` : '';
const grid = (M, hRow, hCol, hCell) => {
  let g = `<div class="mdp-mx-matrix" style="grid-template-columns: repeat(${M[0].length}, auto);">`;
  M.forEach((row, i) => row.forEach((v, j) => {
    const on = (hRow && i === hRow - 1) || (hCol && j === hCol - 1) || (hCell && i === hr - 1 && j === hc - 1);
    g += `<div class="mdp-mx-cell${on ? ' on' : ''}">${fmt(v)}</div>`;
  }));
  return g + `</div>`;
};
const valid = hr >= 1 && hr <= A.length && hc >= 1 && hc <= B[0].length;
let html = `\n\n<div class="mdp-mod-matmul" style="--mx-c:${color};${scaleStyle}">` +
  grid(A, valid ? hr : 0, 0, false) + `<span class="mdp-mx-op">${opSym}</span>` +
  grid(B, 0, valid ? hc : 0, false) + `<span class="mdp-mx-op">=</span>` +
  grid(C, 0, 0, valid) + `</div>\n\n`;
if (valid && String(args.showwork) !== 'false') {
  const terms = A[hr - 1].map((v, k) => `${fmt(v)}·${fmt(B[k][hc - 1])}`).join(' + ');
  html = html.replace(/<\/div>\n\n$/, `<div class="mdp-mx-note">c<sub>${hr}${hc}</sub> = ${terms} = ${fmt(C[hr - 1][hc - 1])}</div></div>\n\n`);
}
return html;
